/**
 * MedX radio runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Coordinates exclusive option groups for shipping priority and payment terms.
 */
const RADIO_PRESETS = Object.freeze({
  shippingPriority: [
    { value: "standard", label: "Standard (5–7 days)", costFactor: 1.0 },
    { value: "expedited", label: "Expedited (2–3 days)", costFactor: 1.8 },
    { value: "overnight", label: "Overnight cold chain", costFactor: 3.2, requiresColdChain: true },
    { value: "critical", label: "Critical emergency", costFactor: 5.0, requiresApproval: true },
  ],
  paymentTerms: [
    { value: "net-30", label: "Net 30", days: 30 },
    { value: "net-60", label: "Net 60", days: 60 },
    { value: "net-90", label: "Net 90", days: 90 },
    { value: "prepaid", label: "Prepaid", days: 0 },
  ],
  complianceLevel: [
    { value: "basic", label: "Basic traceability" },
    { value: "gmp", label: "GMP certified" },
    { value: "fda", label: "FDA 21 CFR Part 11" },
    { value: "eu-mdr", label: "EU MDR compliant" },
  ],
});

const radioGroups = new Map();

function createRadioGroup(config) {
  const preset = RADIO_PRESETS[config.preset];
  if (!preset) throw new Error(`Unknown radio preset: ${config.preset}`);

  const group = {
    id: config.id ?? `medx-radio-${radioGroups.size + 1}`,
    name: config.name ?? config.preset,
    preset: config.preset,
    value: config.defaultValue ?? preset[0].value,
    options: preset.map((opt) => ({ ...opt, id: `${config.id ?? config.preset}-${opt.value}` })),
    disabled: Boolean(config.disabled),
    orientation: config.orientation ?? "vertical",
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  radioGroups.set(group.id, group);
  return group;
}

function setRadioValue(groupId, value) {
  const group = radioGroups.get(groupId);
  if (!group || group.disabled) return false;
  const option = group.options.find((o) => o.value === value);
  if (!option) return false;
  const previous = group.value;
  group.value = value;
  if (group.onChange) group.onChange({ previous, current: value, option });
  return true;
}

function getSelectedOption(groupId) {
  const group = radioGroups.get(groupId);
  if (!group) return null;
  return group.options.find((o) => o.value === group.value) ?? null;
}

function validateRadioSelection(groupId, context = {}) {
  const option = getSelectedOption(groupId);
  if (!option) return { valid: false, reason: "No selection" };
  if (option.requiresColdChain && !context.coldChainEnabled) {
    return { valid: false, reason: "Cold chain not enabled for this shipment" };
  }
  if (option.requiresApproval && !context.hasApproval) {
    return { valid: false, reason: "Manager approval required" };
  }
  return { valid: true, reason: null, option };
}

function serializeRadioGroup(groupId) {
  const group = radioGroups.get(groupId);
  if (!group) return null;
  const selected = getSelectedOption(groupId);
  return {
    id: group.id,
    name: group.name,
    value: group.value,
    label: selected?.label,
    optionCount: group.options.length,
    orientation: group.orientation,
  };
}

async function runMedxRadio() {
  console.log("[medx:ui:radio] runtime initialized");
  console.log(`[medx:ui:radio] presets=${Object.keys(RADIO_PRESETS).length}`);

  const shipping = createRadioGroup({
    id: "ship-priority",
    preset: "shippingPriority",
    defaultValue: "standard",
  });
  const payment = createRadioGroup({
    id: "pay-terms",
    preset: "paymentTerms",
    defaultValue: "net-30",
  });
  const compliance = createRadioGroup({
    id: "compliance",
    preset: "complianceLevel",
    defaultValue: "gmp",
  });

  setRadioValue("ship-priority", "overnight");
  const shipValidation = validateRadioSelection("ship-priority", { coldChainEnabled: true });
  const shipValidationFail = validateRadioSelection("ship-priority", { coldChainEnabled: false });

  console.log(`[medx:ui:radio] groups=${radioGroups.size}`);
  console.log("[medx:ui:radio] shipping", serializeRadioGroup("ship-priority"));
  console.log("[medx:ui:radio] validation", shipValidation.valid, shipValidationFail.reason);
  console.log("[medx:ui:radio] bootstrap complete");
}

module.exports = runMedxRadio;
